#!/usr/bin/env python3"""Focused JIRA access test to find the 'Discount Code in Cart Bug' issue"""import asyncioimport osimport jsonfrom dotenv import load_dotenvfrom autogen_ext.tools.mcp import StdioServerParams, McpWorkbenchload_dotenv()async def test_focused_jira_access():    """Test JIRA access with focused, bounded queries."""    def get_required_env(key: str) -> str:        value = os.getenv(key)        if not value:            raise RuntimeError(f"{key} environment variable not found")        return value    jira_server_params = StdioServerParams(        command="uvx",        args=["mcp-atlassian"],        env={            "JIRA_URL": get_required_env("JIRA_URL"),            "JIRA_USERNAME": get_required_env("JIRA_USERNAME"),            "JIRA_API_TOKEN": get_required_env("JIRA_API_TOKEN"),            "TOOLSETS": "all",        },        read_timeout_seconds=60,    )    async with McpWorkbench(jira_server_params) as jira:        print("🔗 Connected to Jira MCP server")        # List available tools first        print("\n1️⃣ Available JIRA tools...")        try:            tools = await jira.list_tools()            print("Available tools:")            for tool in tools:                if hasattr(tool, 'name'):                    print(f"   🔧 {tool.name}: {tool.description}")                else:                    print(f"   🔧 {tool}")        except Exception as e:            print(f"❌ Error listing tools: {e}")        # Search with project restriction (required)        print("\n2️⃣ Searching for 'Discount Code in Cart Bug' with project restriction...")        try:            search_result = await jira.call_tool(                "jira_search",                {                    "jql": "project = KAN AND (text ~ \"Discount\" OR text ~ \"Cart\" OR summary ~ \"Discount\" OR summary ~ \"Cart\")",                    "fields": "summary,status,priority,created,issuetype,description,key",                    "limit": 50                }            )            if hasattr(search_result, 'result') and search_result.result:                content = search_result.result[0].content                try:                    data = json.loads(content)                    total = data.get('total', 0)                    issues = data.get('issues', [])                    print(f"✅ Found {total} issues matching discount/cart criteria")                    for issue in issues:                        key = issue.get('key', 'Unknown')                        summary = issue.get('fields', {}).get('summary', 'No summary')                        status = issue.get('fields', {}).get('status', {}).get('name', 'No status')                        description = issue.get('fields', {}).get('description', '')                        print(f"   🎫 {key}: {summary} [Status: {status}]")                        if description:                            print(f"      📝 Description: {description[:100]}...")                except json.JSONDecodeError as e:                    print(f"❌ JSON decode error: {e}")                    print(f"Content: {content}")            else:                print(f"❌ No results from search")        except Exception as e:            print(f"❌ Error searching for discount bug: {e}")        # Search all issues in KAN project with time bounds        print("\n3️⃣ All KAN project issues (last 90 days)...")        try:            search_result = await jira.call_tool(                "jira_search",                {                    "jql": "project = KAN AND created >= -90d",                    "fields": "summary,status,priority,created,issuetype,key",                    "limit": 100                }            )            if hasattr(search_result, 'result') and search_result.result:                content = search_result.result[0].content                try:                    data = json.loads(content)                    total = data.get('total', 0)                    issues = data.get('issues', [])                    print(f"✅ Found {total} total issues in KAN project (last 90 days)")                    # Look specifically for discount/cart related issues                    discount_issues = []                    for issue in issues:                        key = issue.get('key', 'Unknown')                        summary = issue.get('fields', {}).get('summary', 'No summary')                        status = issue.get('fields', {}).get('status', {}).get('name', 'No status')                        # Check if this could be the discount bug                        summary_lower = summary.lower()                        if any(keyword in summary_lower for keyword in ['discount', 'cart', 'bug', 'code']):                            discount_issues.append(issue)                            print(f"   🎯 {key}: {summary} [Status: {status}] ⭐ POTENTIAL MATCH")                        else:                            print(f"   🎫 {key}: {summary} [Status: {status}]")                    if discount_issues:                        print(f"\n🎯 Found {len(discount_issues)} potential discount/cart related issues!")                        for issue in discount_issues:                            key = issue.get('key')                            print(f"\n📄 Getting details for {key}...")                            try:                                issue_detail = await jira.call_tool("jira_get_issue", {"key": key})                                if hasattr(issue_detail, 'result') and issue_detail.result:                                    detail_content = issue_detail.result[0].content                                    try:                                        detail_data = json.loads(detail_content)                                        summary = detail_data.get('fields', {}).get('summary', 'N/A')                                        description = detail_data.get('fields', {}).get('description', 'No description')                                        print(f"   📋 Summary: {summary}")                                        print(f"   📝 Description: {description}")                                    except json.JSONDecodeError:                                        print(f"   ❌ Could not parse details for {key}")                            except Exception as e:                                print(f"   ❌ Error getting details for {key}: {e}")                except json.JSONDecodeError as e:                    print(f"❌ JSON decode error: {e}")                    print(f"Content: {content}")            else:                print("❌ No results from KAN project search")        except Exception as e:            print(f"❌ Error in KAN project search: {e}")        # Try searching without time bounds but with project        print("\n4️⃣ All KAN project issues (no time bounds)...")        try:            search_result = await jira.call_tool(                "jira_search",                {                    "jql": "project = KAN",                    "fields": "summary,status,priority,created,issuetype,key",                    "limit": 100                }            )            if hasattr(search_result, 'result') and search_result.result:                content = search_result.result[0].content                try:                    data = json.loads(content)                    total = data.get('total', 0)                    issues = data.get('issues', [])                    print(f"✅ Found {total} total issues in KAN project (all time)")                    # Look for the exact bug                    for issue in issues:                        key = issue.get('key', 'Unknown')                        summary = issue.get('fields', {}).get('summary', 'No summary')                        status = issue.get('fields', {}).get('status', {}).get('name', 'No status')                        # Check for exact match                        if "discount code in cart bug" in summary.lower():                            print(f"   🎯 EXACT MATCH: {key}: {summary} [Status: {status}]")                        elif any(word in summary.lower() for word in ['discount', 'cart', 'bug']):                            print(f"   🔍 POTENTIAL: {key}: {summary} [Status: {status}]")                        else:                            print(f"   📄 {key}: {summary} [Status: {status}]")                except json.JSONDecodeError as e:                    print(f"❌ JSON decode error: {e}")                    print(f"Content: {content}")            else:                print("❌ No results from KAN project search")        except Exception as e:            print(f"❌ Error in KAN project search: {e}")if __name__ == "__main__":    asyncio.run(test_focused_jira_access())